const PROMPT_HEAD = [
"ROLE: You are HINDSIGHT, a senior cybersecurity incident-log intelligence analyst.",
"You extract facts from SIEM exports, vulnerability scans (Nessus/Qualys/Tenable),",
"phishing investigations, malware findings, and intrusion writeups.",
"",
"TASK: Read the document and return structured incident intelligence for SecOps triage.",
"",
"OUTPUT FORMAT: Return ONLY a valid JSON object — no markdown, no code fences, no commentary.",
"Use EXACTLY these fields:",
"{",
'  "incident_title": "short title for the finding or incident",',
'  "summary": "2-3 sentence summary of what happened and the impact",',
'  "severity": "one of: [SEV1, SEV2, SEV3, SEV4]",',
'  "incident_type": "one of: [security, data-incident, vulnerability-scan, malware, phishing, intrusion, ddos, other]",',
'  "status": "one of: [resolved, monitoring, ongoing]",',
'  "affected_services": ["systems or services named in the document"],',
'  "affected_jurisdictions": ["GLOBAL only if explicitly scoped"],',
'  "root_cause": "underlying root cause in one or two sentences",',
'  "trigger": "what triggered the alert or finding",',
'  "detection_method": "one of: [alert, monitoring, customer-report, manual, synthetic, unknown]",',
'  "entities": {"people": [], "teams": [], "systems": [], "dates": [], "error_codes": []},',
'  "action_items": [{"action": "follow-up action", "owner": "owner or null", "priority": "one of: [P0, P1, P2] or null"}],',
'  "contributing_factors": [],',
'  "sentiment": "one of: [positive, neutral, negative]",',
'  "blameless_quality": "one of: [good, acceptable, poor, unknown]",',
'  "cvss_score": null,',
'  "cve_ids": [],',
'  "confidence_score": 0.0,',
'  "metrics": {"detected_at": "ISO or null", "resolved_at": "ISO or null", "ttd_minutes": 0, "ttr_minutes": 0, "customer_impact": "one sentence or null"}',
"}",
"",
"RULES:",
"- incident_type maps to downstream classification (e.g. vulnerability-scan, phishing, intrusion).",
"- For vuln scans: set cvss_score and cve_ids verbatim when present; never invent CVEs.",
"- SEV1 = active compromise, critical vuln (CVSS >= 9), or major data exposure; when unsure pick LOWER severity.",
"- Use null (not empty string) for unknown scalar values; use [] for empty arrays.",
"- Do not invent systems, hosts, people, or metrics not stated in the document.",
"- Write summary in clear, professional language suitable for an on-call handoff.",
""
].join("\\n");

const MAX_DOCUMENT_CHARS = 900000;

function truncateDocumentText(text) {
  const raw = String(text || "");
  if (raw.length <= MAX_DOCUMENT_CHARS) return raw;
  return raw.slice(0, MAX_DOCUMENT_CHARS)
    + "\n\n[TRUNCATED: document exceeded " + MAX_DOCUMENT_CHARS + " chars; tail omitted before Gemini]";
}

function readU16(buf, off) { return buf[off] | (buf[off + 1] << 8); }
function readU32(buf, off) {
  return (buf[off] | (buf[off + 1] << 8) | (buf[off + 2] << 16) | (buf[off + 3] << 24)) >>> 0;
}
function unzipTextEntries(buf) {
  const entries = [];
  let eocd = buf.length;
  for (let i = buf.length - 22; i >= 0; i--) {
    if (readU32(buf, i) === 0x06054b50) { eocd = i; break; }
  }
  let offset = 0;
  while (offset + 30 < eocd) {
    if (readU32(buf, offset) !== 0x04034b50) break;
    const comp = readU16(buf, offset + 8);
    const compSize = readU32(buf, offset + 18);
    const nameLen = readU16(buf, offset + 26);
    const extraLen = readU16(buf, offset + 28);
    const name = buf.slice(offset + 30, offset + 30 + nameLen).toString("utf8");
    const dataStart = offset + 30 + nameLen + extraLen;
    const data = buf.slice(dataStart, dataStart + compSize);
    offset = dataStart + compSize;
    if (name.endsWith("/")) continue;
    const ext = name.indexOf(".") >= 0 ? name.split(".").pop().toLowerCase() : "";
    if (ext !== "md" && ext !== "txt" && ext !== "markdown") continue;
    let raw;
    if (comp === 0) {
      raw = data;
    } else if (comp === 8) {
      throw new Error("DEFLATE zip entries blocked on n8n Cloud — re-pack with ZIP_STORED (see samples/make_batch_zip.py)");
    } else {
      continue;
    }
    entries.push({ filename: name.split("/").pop(), text: raw.toString("utf8") });
    if (entries.length >= 25) {
      if (offset + 30 < eocd && readU32(buf, offset) === 0x04034b50) {
        throw new Error(
          "ZIP batch exceeds 25 supported .md/.txt files — split the archive or use the self-hosted batch API"
        );
      }
      break;
    }
  }
  return entries;
}

const TEXT_EXTS = { md: 1, txt: 1, markdown: 1 };

function newCorrelationId() {
  if (globalThis.crypto && typeof globalThis.crypto.randomUUID === "function") {
    return globalThis.crypto.randomUUID();
  }
  return "hs-" + Date.now() + "-" + Math.floor(Math.random() * 1e6);
}

function buildGeminiBody(documentText, isPdf, b64) {
  let parts;
  if (isPdf) {
    const promptText = PROMPT_HEAD
      + "VISION NOTES: The source PDF is attached. Read any embedded SIEM or scan charts and fold metrics into summary.\n"
      + "DOCUMENT: (see attached PDF)";
    parts = [{ text: promptText }, { inline_data: { mime_type: "application/pdf", data: b64 } }];
  } else {
    const promptText = PROMPT_HEAD
      + "VISION NOTES: (none)\n"
      + "DOCUMENT TEXT:\n" + truncateDocumentText(documentText);
    parts = [{ text: promptText }];
  }
  return {
    contents: [{ role: "user", parts: parts }],
    generationConfig: { temperature: 0.2, responseMimeType: "application/json" }
  };
}

const items = $input.all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const pre = item.json || {};

  // Batch fan-out item from Unzip Batch node (BON-7)
  if (pre.isBatchItem && pre.documentText) {
    out.push({ json: {
      correlationId: newCorrelationId(),
      sourceFilename: pre.sourceFilename || "batch-item.md",
      mimeType: "text/plain",
      isPdf: false,
      isBatchItem: true,
      batchIndex: pre.batchIndex,
      batchTotal: pre.batchTotal,
      receivedAt: new Date().toISOString(),
      geminiBody: buildGeminiBody(pre.documentText, false, null),
    } });
    continue;
  }

  const bin = item.binary || {};
  const keys = Object.keys(bin);
  if (keys.length === 0) {
    throw new Error("No file was uploaded. Please attach a cyber incident log (.pdf, .md, .txt, or .zip).");
  }
  const key = keys[0];
  const meta = bin[key] || {};
  const fileName = meta.fileName || "incident-log";
  const mimeType = String(meta.mimeType || "").toLowerCase();
  const ext = String(meta.fileExtension || (fileName.split(".").pop() || "")).toLowerCase();

  if (ext === "docx") {
    throw new Error(
      "DOCX is not supported on n8n Cloud (grading path). "
      + "Use the self-hosted stack (docker compose + incoming_docs/) which extracts DOCX via python-docx."
    );
  }

  // Extension is authoritative — avoids MIME/extension mismatch (e.g. .txt labeled application/pdf).
  const isPdf = ext === "pdf";
  const isZip = ext === "zip";
  const isText = !!TEXT_EXTS[ext];

  if (!isPdf && !isZip && !isText) {
    throw new Error(
      "Unsupported file type"
      + (ext ? ` ".${ext}"` : "")
      + ". Allowed on Cloud: .pdf, .md, .txt, .markdown, .zip"
    );
  }

  let buf;
  try {
    buf = await this.helpers.getBinaryDataBuffer(idx, key);
  } catch (e) {
    buf = Buffer.from(meta.data || "", "base64");
  }

  if (!buf || buf.length === 0) {
    throw new Error("Uploaded file is empty (0 bytes). Please attach a non-empty incident log.");
  }

  if (isZip) {
    const entries = unzipTextEntries(buf);
    if (!entries.length) throw new Error("ZIP contained no supported .md/.txt files");
    for (let i = 0; i < entries.length; i++) {
      out.push({ json: {
        correlationId: newCorrelationId(),
        sourceFilename: entries[i].filename,
        mimeType: "text/plain",
        isPdf: false,
        isBatchItem: true,
        batchIndex: i,
        batchTotal: entries.length,
        receivedAt: new Date().toISOString(),
        geminiBody: buildGeminiBody(entries[i].text, false, null),
      } });
    }
    continue;
  }

  let geminiBody;
  if (isPdf) {
    geminiBody = buildGeminiBody("", true, buf.toString("base64"));
  } else if (isText) {
    geminiBody = buildGeminiBody(buf.toString("utf-8"), false, null);
  } else {
    throw new Error("Unsupported file type — expected .pdf, .md, .txt, .markdown, or .zip");
  }

  out.push({ json: {
    correlationId: newCorrelationId(),
    sourceFilename: fileName,
    mimeType: mimeType,
    isPdf: isPdf,
    receivedAt: new Date().toISOString(),
    geminiBody: geminiBody,
  } });
}
return out;

const FENCE = String.fromCharCode(96, 96, 96);
const REQUIRED = ["summary", "sentiment", "action_items", "confidence_score", "entities"];
const VALID_SENTIMENT = { positive: 1, neutral: 1, negative: 1 };

function validateGeminiShape(g) {
  const missing = [];
  for (let i = 0; i < REQUIRED.length; i++) {
    if (g[REQUIRED[i]] === undefined) missing.push(REQUIRED[i]);
  }
  if (!g.incident_type && !g.classification) missing.push("incident_type|classification");
  if (!Array.isArray(g.action_items)) missing.push("action_items(array)");
  if (!g.entities || typeof g.entities !== "object" || Array.isArray(g.entities)) {
    missing.push("entities(object)");
  }
  if (missing.length) {
    throw new Error("Gemini JSON missing required fields: " + missing.join(", "));
  }
  if (typeof g.confidence_score === "number" && (g.confidence_score < 0 || g.confidence_score > 1)) {
    throw new Error("confidence_score must be between 0 and 1");
  }
}

function normalizeSentiment(raw) {
  const s = String(raw || "neutral").toLowerCase();
  return VALID_SENTIMENT[s] ? s : "neutral";
}

const items = $input.all();
const prep = $("Prepare Document").all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const resp = items[idx].json || {};
  let raw = "";
  try {
    raw = resp.candidates[0].content.parts[0].text || "";
  } catch (e) {
    raw = "";
  }
  raw = String(raw).trim();
  // Strip only a WRAPPING ```json … ``` fence pair — never a global backtick
  // delete (that would corrupt inner SIEM command blocks in string values).
  if (raw.indexOf(FENCE) === 0) {
    raw = raw.slice(FENCE.length);
    if (raw.toLowerCase().indexOf("json") === 0) { raw = raw.slice(4); }
    const end = raw.lastIndexOf(FENCE);
    if (end !== -1) { raw = raw.slice(0, end); }
    raw = raw.trim();
  }
  let g;
  try {
    g = JSON.parse(raw);
  } catch (e) {
    throw new Error("Gemini did not return valid JSON. First 200 chars: " + raw.slice(0, 200));
  }
  validateGeminiShape(g);
  // Gemini may return the §5.4 `classification` field instead of our `incident_type`.
  // Map it so enrich.js routes/floors correctly instead of defaulting to "other".
  if (!g.incident_type && g.classification) { g.incident_type = String(g.classification); }
  g.sentiment = normalizeSentiment(g.sentiment);
  const p = (prep[idx] && prep[idx].json) ? prep[idx].json : {};
  g.correlation_id = p.correlationId || null;
  g.source_filename = p.sourceFilename || null;
  out.push({ json: g });
}
return out;

// HINDSIGHT enrichment - faithful port of the FastAPI /enrich brain.
// Pure computation (no network). Mirrors services/enrichment-api in the repo.
const DEFAULTS = { team: "SecOps", tier: "standard", slo: 99.0, jurisdictions: ["GLOBAL"] };
const SERVICES = [
  { name: "siem", aliases: ["splunk","elastic siem","security monitoring","log pipeline","wazuh","sentinel","siem cluster"], team: "SecOps", tier: "high", slo: 99.5, jurisdictions: ["GLOBAL"] },
  { name: "endpoint-security", aliases: ["edr","antivirus","av","crowdstrike","defender","endpoint protection","xdr","hosts"], team: "SecOps", tier: "high", slo: 99.5, jurisdictions: ["GLOBAL"] },
  { name: "vulnerability-scanner", aliases: ["nessus","qualys","vuln scanner","tenable","scanner","trivy","snyk","openvas"], team: "SecOps", tier: "standard", slo: 99.0, jurisdictions: ["GLOBAL"] },
  { name: "auth", aliases: ["identity","login","sso","idp","authentication","session-service","oauth"], team: "Identity-Sec", tier: "high", slo: 99.5, jurisdictions: ["GLOBAL"] },
  { name: "network", aliases: ["firewall","ids","ips","waf","perimeter","edge","cdn","ingress"], team: "NetSec", tier: "high", slo: 99.5, jurisdictions: ["GLOBAL"] },
  { name: "email-gateway", aliases: ["mail relay","smtp","phishing filter","mimecast","email security","proofpoint"], team: "SecOps", tier: "standard", slo: 99.0, jurisdictions: ["GLOBAL"] },
  { name: "internal-tooling", aliases: ["jenkins","ci","grafana","internal dashboard","soar","ticketing"], team: "SecOps", tier: "internal", slo: 99.0, jurisdictions: ["GLOBAL"] }
];
const TYPE_ROUTING = { "security":"Security-IR","data-incident":"Security-IR","vulnerability-scan":"SecOps","malware":"SecOps","phishing":"SecOps","intrusion":"Security-IR","ddos":"NetSec","outage":"SecOps","degradation":"SecOps","configuration":"SecOps","other":"SecOps" };
// Cyber hybrid: types implying data exposure (-> confidential) / active compromise (-> severity floor).
const SECURITY_SENSITIVE_TYPES = { "security":1,"data-incident":1,"intrusion":1,"malware":1,"phishing":1 };
const SECURITY_FLOOR_TYPES = { "security":1,"data-incident":1,"intrusion":1,"malware":1 };
const REVIEW_THRESHOLD = 0.7;
const BUDGET_BREACH_FRACTION = 0.5;

function norm(t) {
  t = String(t || "").toLowerCase().trim();
  t = t.replace(/[_\-\/]+/g, " ");
  t = t.replace(/[^a-z0-9 ]+/g, "");
  t = t.replace(/\s+/g, " ");
  return t.trim();
}
const LOOKUP = {};
for (const e of SERVICES) {
  const keys = [e.name].concat(e.aliases || []);
  for (const k of keys) { LOOKUP[norm(k)] = e; }
}
function wordIn(needle, hay) {
  if (!needle) return false;
  const esc = needle.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return new RegExp("\\b" + esc + "\\b").test(hay);
}
function resolveOne(name) {
  if (!name) return null;
  const key = norm(name);
  if (LOOKUP[key]) return LOOKUP[key];
  // Whole-word match only (parity with routing.py): 'av' must not match 'average'.
  for (const ak of Object.keys(LOOKUP)) {
    if (ak && (wordIn(ak, key) || wordIn(key, ak))) return LOOKUP[ak];
  }
  return null;
}
function resolveMany(names) {
  const seen = {};
  const order = [];
  for (const n of (names || [])) {
    const e = resolveOne(n);
    if (e && !seen[e.name]) { seen[e.name] = e; order.push(e); }
  }
  return order;
}

const TIER_SCORE = { critical: 4, high: 3, standard: 2, internal: 1 };
const SEV_RANK = { SEV4: 4, SEV3: 3, SEV2: 2, SEV1: 1 };
const HIGH_IMPACT = [
  /\bdata (loss|breach|leak)\b/, /\bbreach\b/, /\bpii\b/, /\bregulator(y)?\b/, /\bfine[sd]?\b/,
  /\bfunds?\b/, /\bmonetary\b/, /\bdouble[- ]charg/, /\brevenue\b/, /\bpayment[s]? (fail|down|unavailable)/,
  /\bcomplete (outage|down)/, /\btotal outage\b/, /\ball (users|players|customers)\b/
];
function impactHits(text) {
  text = String(text || "").toLowerCase();
  let n = 0;
  for (const re of HIGH_IMPACT) { if (re.test(text)) n++; }
  return n;
}

function round1(x) { return Math.round(x * 10) / 10; }
function round3(x) { return Math.round(x * 1000) / 1000; }

function cvssBand(cvss) {
  if (cvss >= 9.0) return "SEV1";
  if (cvss >= 7.0) return "SEV2";
  if (cvss >= 4.0) return "SEV3";
  return null;
}

function scoreSeverity(reported, incidentType, resolved, jurisdictions, ttr, summary, cvss) {
  let score = 0;
  const rationale = [];
  if (resolved.length) {
    let top = resolved[0];
    for (const e of resolved) { if ((TIER_SCORE[e.tier]||1) > (TIER_SCORE[top.tier]||1)) top = e; }
    const pts = TIER_SCORE[top.tier] || 1;
    score += pts;
    rationale.push("highest-tier service '" + top.name + "' is " + top.tier + " (+" + pts + ")");
  } else {
    rationale.push("no catalogued service matched (+0)");
  }
  const realJx = (jurisdictions || []).filter(function (j) { return j && j.toUpperCase() !== "GLOBAL"; });
  if (realJx.length >= 2) { score += 3; rationale.push("multi-jurisdiction impact (" + realJx.join(", ") + ") (+3)"); }
  else if (realJx.length === 1) { score += 1; rationale.push("single-jurisdiction impact (" + realJx[0] + ") (+1)"); }
  const hits = impactHits(summary);
  if (hits) { const pts = Math.min(hits * 2, 4); score += pts; rationale.push("high-impact language (" + hits + " signal/s) (+" + pts + ")"); }
  const t = ttr || 0;
  if (t >= 120) { score += 3; rationale.push("downtime " + Math.round(t) + " min >= 2h (+3)"); }
  else if (t >= 30) { score += 2; rationale.push("downtime " + Math.round(t) + " min >= 30m (+2)"); }
  else if (t > 0) { score += 1; rationale.push("downtime " + Math.round(t) + " min (+1)"); }
  if (SECURITY_FLOOR_TYPES[incidentType]) { score += 3; rationale.push("incident type '" + incidentType + "' carries regulatory weight (+3)"); }

  let cvssFloor = null;
  if (cvss !== null && cvss !== undefined && Number(cvss) > 0) {
    cvssFloor = cvssBand(Number(cvss));
    const cvssPts = { SEV1: 5, SEV2: 3, SEV3: 1 }[cvssFloor] || 0;
    if (cvssPts) { score += cvssPts; rationale.push("CVSS " + Number(cvss).toFixed(1) + " (" + cvssFloor + "-class) (+" + cvssPts + ")"); }
    else { rationale.push("CVSS " + Number(cvss).toFixed(1) + " low (+0)"); }
  }

  let computed;
  if (score >= 9) computed = "SEV1";
  else if (score >= 6) computed = "SEV2";
  else if (score >= 3) computed = "SEV3";
  else computed = "SEV4";

  if (cvssFloor && SEV_RANK[cvssFloor] < SEV_RANK[computed]) {
    computed = cvssFloor;
    rationale.push("severity floored to " + cvssFloor + " by CVSS " + Number(cvss).toFixed(1));
  }

  const delta = Math.abs(SEV_RANK[computed] - (SEV_RANK[reported] || 3));
  const review = delta >= 1;
  if (review) {
    const dir = SEV_RANK[computed] < (SEV_RANK[reported] || 3) ? "higher" : "lower";
    rationale.push("rubric (" + computed + ") is " + dir + " than reported (" + reported + ") -> review");
  }
  return { computed: computed, score: score, rationale: rationale, review: review };
}

function classifySensitivity(incidentType, jurisdictions, entitiesBlob, summary, cvss, cveIds) {
  const text = (String(summary || "") + " " + String(entitiesBlob || "")).toLowerCase();
  const realJx = (jurisdictions || []).filter(function (j) { return j && j.toUpperCase() !== "GLOBAL"; });
  const signals = [
    ["security-class incident (" + incidentType + ")", !!SECURITY_SENSITIVE_TYPES[incidentType]],
    ["PII / customer-data reference", /\b(pii|customer data|personal data)\b/.test(text)],
    ["monetary / payment exposure", /\b(funds?|payments?|charges?|refunds?|monetary)\b/.test(text)],
    ["regulatory exposure", /\b(regulator\w*|ukgc|dge|fines?|fined)\b/.test(text)],
    ["multi-jurisdiction", realJx.length >= 2],
    ["high-severity CVE (CVSS >= 7.0)", cvss !== null && cvss !== undefined && Number(cvss) >= 7.0],
    ["CVE identifiers cited", Array.isArray(cveIds) && cveIds.length > 0],
  ];
  const triggered = [];
  for (const s of signals) { if (s[1]) triggered.push(s[0]); }
  if (triggered.length) return { sensitivity: "confidential", rationale: triggered };
  const nonSensitive = !SECURITY_SENSITIVE_TYPES[incidentType];
  const globalOnly = !realJx.length;
  if (nonSensitive && globalOnly) {
    return { sensitivity: "public", rationale: ["non-sensitive incident, no confidential markers, GLOBAL-only scope"] };
  }
  return { sensitivity: "internal", rationale: ["operational incident, no confidential markers"] };
}

function sloImpact(primary, ttr) {
  if (!primary) return { primary_service: null, slo_target: null, monthly_budget_minutes: null, budget_burn_minutes: null, budget_burn_pct: null, budget_breach: false };
  const minutesPerMonth = 30 * 24 * 60;
  const budget = round1(minutesPerMonth * (1 - primary.slo / 100.0));
  const burn = Number(ttr || 0);
  const burnPct = budget > 0 ? round1((burn / budget) * 100) : null;
  const breach = budget > 0 && burn >= budget * BUDGET_BREACH_FRACTION;
  return { primary_service: primary.name, slo_target: primary.slo, monthly_budget_minutes: budget, budget_burn_minutes: round1(burn), budget_burn_pct: burnPct, budget_breach: breach };
}

const STOP = { "the":1,"a":1,"an":1,"of":1,"to":1,"in":1,"on":1,"and":1,"or":1,"for":1,"was":1,"were":1,"is":1,"due":1,"caused":1,"by":1,"this":1,"that":1,"with":1,"from":1,"after":1,"led":1,"which":1,"resulted":1,"incident":1,"issue":1,"error":1,"failure":1 };
function fingerprint(services, rootCause, incidentType) {
  const tokens = String(rootCause || "").toLowerCase().replace(/[^a-z0-9 ]+/g, " ").split(/\s+/).filter(Boolean);
  const uniq = {};
  for (const t of tokens) { if (!STOP[t] && t.length > 2) uniq[t] = 1; }
  const kw = Object.keys(uniq).sort().slice(0, 6);
  const basis = [incidentType].concat(services.slice().sort()).concat(kw).join("|");
  const crypto = require("crypto");
  return crypto.createHash("sha1").update(basis, "utf8").digest("hex").slice(0, 12);
}

function adjustConfidence(g) {
  let conf = Number(g.confidence_score || 0);
  const notes = [];
  let penalty = 0;
  if (!String(g.root_cause || "").trim()) { penalty += 0.20; notes.push("missing root cause (-0.20)"); }
  if (!(g.action_items && g.action_items.length)) { penalty += 0.10; notes.push("no action items extracted (-0.10)"); }
  if (!(g.affected_services && g.affected_services.length)) { penalty += 0.10; notes.push("no affected services identified (-0.10)"); }
  const m = g.metrics || {};
  const metricsPresent = !!(m.detected_at || m.resolved_at || (m.ttd_minutes !== null && m.ttd_minutes !== undefined) || (m.ttr_minutes !== null && m.ttr_minutes !== undefined));
  if (!metricsPresent) { penalty += 0.05; notes.push("no timing metrics (-0.05)"); }
  let adjusted = Math.max(0, Math.min(1, conf - penalty));
  if (adjusted < REVIEW_THRESHOLD) notes.push("below review threshold " + REVIEW_THRESHOLD);
  return { adjusted: round3(adjusted), delta: round3(adjusted - conf), notes: notes, present: metricsPresent };
}

function uuid() {
  if (globalThis.crypto && typeof globalThis.crypto.randomUUID === "function") return globalThis.crypto.randomUUID();
  return "doc-" + Date.now() + "-" + Math.floor(Math.random() * 1e6);
}

const items = $input.all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const g = items[idx].json || {};
  const ent = g.entities || {};
  const resolved = resolveMany(g.affected_services || []);
  const resolvedNames = resolved.map(function (e) { return e.name; });
  let teams = Array.from(new Set(resolved.map(function (e) { return e.team; }))).sort();
