    department: department,
    routed_teams: teams,
    affected_services_resolved: resolvedNames,
    affected_jurisdictions: jurisdictions,
    sensitivity: sens.sensitivity,
    sensitivity_rationale: sens.rationale,
    slo_impact: slo,
